import{_ as a,o as l,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"196. Travelling Allowances","description":"","frontmatter":{"title":"196. Travelling Allowances","eba":"Mental Health Services 2024-2028","topics":["allowances","vehicle"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/allowances/196-travelling-allowances.md","filePath":"ebas/mental-health/management-admin/allowances/196-travelling-allowances.md"}'),r={name:"ebas/mental-health/management-admin/allowances/196-travelling-allowances.md"};function n(s,e,i,h,c,m){return l(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_196-travelling-allowances" tabindex="-1">196. Travelling Allowances <a class="header-anchor" href="#_196-travelling-allowances" aria-label="Permalink to &quot;196. Travelling Allowances&quot;">​</a></h1><p><strong>196.1</strong> Should an Employee be required to use their own vehicle for transport from home to place of work and return outside of normal hours, the Employee is to receive the allowance as set out in <a href="/eba/ebas/mental-health/common-terms/allowances/34-vehicle-allowance.html">clause 34</a>.</p><p><strong>196.2</strong> An Employee who is recalled to the workplace for any purpose shall be either provided with appropriate transport for the outward and return journeys with the cost met by their Employer or where the Employee uses their own vehicle for transport from home to place of work and return the Employee is to receive the allowance as set out in <a href="/eba/ebas/mental-health/common-terms/allowances/34-vehicle-allowance.html">clause 34</a>.</p><p><strong>196.3</strong> Where an Employee is required to travel during ordinary hours for work-purposes, they shall be provided either with appropriate transport by their Employer or if the Employee agrees to use their own motor vehicle, they shall be paid the vehicle allowances set out in <a href="/eba/ebas/mental-health/common-terms/allowances/34-vehicle-allowance.html">clause 34</a>.</p><p><strong>196.4</strong> An Employee required to travel on business in the performance of their duties shall be reimbursed all reasonable travelling expenses necessarily incurred.</p>',5)])])}const w=a(r,[["render",n]]);export{d as __pageData,w as default};
